create table dirkspzm32.isi_artikel (
    sid                        varchar2(2 char) default '01' not null enable,
    artikel_id                 number(*, 0) not null enable,
    artikel                    varchar2(30 char) not null enable,
    bezeichnung1               varchar2(50 char),
    bezeichnung2               varchar2(50 char),
    bezeichnung3               varchar2(50 char),
    materialart                varchar2(20 char),
    lhm_name                   varchar2(50 char),
    lhm_menge                  number(*, 3) default 1 not null enable,
    lhm_gewicht_kg             number(*, 6) default 1 not null enable,
    lhm_ean                    varchar2(15 char),
    lte_name                   varchar2(22 char),
    lte_menge                  number(*, 3) default 1 not null enable,
    lte_gewicht_kg             number(*, 6) default 1 not null enable,
    lte_breite_max             number(*, 3) default 1 not null enable,
    lte_tiefe_max              number(*, 3) default 1 not null enable,
    lte_hoehe_max              number(*, 3) default 1 not null enable,
    lte_lhm_menge              number(*, 6) default 1 not null enable,
    lte_lhm_pro_lage           number(*, 5) default 1 not null enable,
    lte_lhm_lagen              number(*, 5) default 1 not null enable,
    lte_ean                    varchar2(15 char),
    wert_klasse                number(*, 0) default 0 not null enable,
    gefahren_klasse            number(*, 0) default 0 not null enable,
    mengeneinheit              varchar2(3 char) default 'STK' not null enable,
    waren_gruppe               varchar2(10 char),
    waren_typ                  varchar2(3 char) default 'FW' not null enable,
    lgr_such_grp               varchar2(1 char),
    lgr_letzter_platz          varchar2(30 char),
    abc                        number(*, 0) default 1 not null enable,
    mhd_tage                   number(10, 0) default 1 not null enable,
    labor_vorgabe_status       varchar2(1 char) default 'F' not null enable,
    reife_zeit_tage            number(*, 12) default 0 not null enable,
    ean                        varchar2(15 char),
    min_temp                   number(5, 1) default - 300,
    max_temp                   number(5, 1) default 300,
    einlagerung                varchar2(2 char) default 'AR',
    min_bestand                number(*, 5) default 0 not null enable,
    max_bestand                number(*, 5) default 0 not null enable,
    einlager_tage              number(*, 5) default 0,
    artikel_kurz               varchar2(20 char),
    menge_basis                varchar2(3 char) default 'LKE' not null enable,
    mengeneinheit_basis        varchar2(10 char) default 'STK' not null enable,
    lagerorte                  varchar2(70 char) default 'ALLE;' not null enable,
    mhd_berechnung             varchar2(2 char) default 'TA',
    artikel_p1                 varchar2(50 char),
    artikel_p2                 varchar2(50 char),
    artikel_p3                 varchar2(50 char),
    artikel_p4                 varchar2(50 char),
    artikel_p5                 varchar2(50 char),
    artikel_p6                 varchar2(50 char),
    artikel_p7                 varchar2(50 char),
    artikel_p8                 varchar2(50 char),
    artikel_p9                 varchar2(50 char),
    artikel_p10                varchar2(50 char),
    inventur_datum             date,
    inventur_user_id           number(*, 0),
    min_mhd_tage_ausl          number(*, 5),
    min_mhd_tage_ms            number(*, 5),
    aktiv                      varchar2(1 char) default 'T' not null enable,
    zeichnung                  varchar2(255 char),
    zeichnung_index            varchar2(10 char),
    lhm_hoehe_lage             number(*, 3),
    anz_etikett_je_lte         number(*, 5),
    akt_inventur_id            number(*, 0),
    letzte_inventur_id         number(*, 0),
    lte_namen                  varchar2(200 char),
    lhm_namen                  varchar2(200 char),
    mhd_festes_datum           date,
    res_artikel                varchar2(1 char),
    res_charge                 varchar2(1 char),
    res_serie                  varchar2(1 char),
    res_fa_auftrag             varchar2(1 char),
    res_kunde                  varchar2(1 char),
    res_mhd                    varchar2(1 char),
    res_mhd_tage               number(*, 5),
    abfuell_abschalt_grob      number(*, 5),
    abfuell_abschalt_mittel    number(*, 5),
    abfuell_abschalt_fein      number(*, 5),
    abfuell_toleranz_plus      number(*, 6),
    abfuell_toleranz_minus     number(*, 6),
    abfuell_soll               number(*, 6),
    art_gruppe_id              number(*, 0),
    einzelgewicht_g            number(*, 6),
    ersatzteil                 varchar2(1 char) default 'U' not null enable,
    preis_standard             number(*, 5),
    preis_gleitend             number(*, 5),
    res_string                 varchar2(80 char),
    erz_datum                  date,
    erz_login_id               number(*, 0) default - 1 not null enable,
    aend_datum                 date,
    aend_login_id              number(*, 0),
    lgr_ort_vorgabe            number(5, 0),
    verk_preis                 number(*, 5),
    verk_rabatt_faktor         number(*, 6),
    default_lieferant_id       number(*, 0),
    packschema_kopf_id         varchar2(20 char),
    art_laenge                 number(*, 3),
    art_breite                 number(*, 3),
    art_dicke                  number(*, 3),
    art_durch                  number(*, 3),
    pack_vorschr               varchar2(15 char),
    herstell_kosten            number(*, 5),
    beschaffungs_kosten        number(*, 5),
    wieder_besch               number(10, 0),
    stueckzahl_pro_preis       number(*, 5) default 1 not null enable,
    opt_grp                    varchar2(50 char),
    lhm_tara                   number(*, 6),
    einsatzgewicht_kg          number(*, 6),
    leg_zuschlag_p_1000kg      number(*, 5),
    leg_zuschlag_artikel_id    number(*, 0),
    artikel_fuer_kunde         number(*, 0),
    laufrichtung               char(1 byte),
    lam_sel1                   varchar2(30 char),
    lam_sel2                   varchar2(30 char),
    lam_sel3                   varchar2(30 char),
    lam_sel4                   varchar2(30 char),
    lam_sel5                   varchar2(30 char),
    lam_sel6                   varchar2(30 char),
    lam_sel7                   varchar2(30 char),
    lam_sel8                   varchar2(30 char),
    lam_sel9                   varchar2(30 char),
    lam_sel10                  varchar2(30 char),
    artikel_fuer_kunde_etikett varchar2(20 char)
);

alter table dirkspzm32.isi_artikel
    add constraint check_isi_artikel_menge_basis
        check ( menge_basis in ( 'LKE', 'LHM', 'LTE' ) ) enable;

alter table dirkspzm32.isi_artikel
    add constraint check_labor_vorgabe_status
        check ( labor_vorgabe_status in ( 'Q', 'U', 'B', 'G', 'F' ) ) enable;

alter table dirkspzm32.isi_artikel
    add constraint check_laufrichtung
        check ( laufrichtung in ( '', 'M', 'O', 'E' ) ) enable;

alter table dirkspzm32.isi_artikel
    add constraint chk_isi_artikel_abc
        check ( abc in ( 1, 2, 3 ) ) enable;

alter table dirkspzm32.isi_artikel
    add constraint chk_isi_artikel_aktiv
        check ( aktiv in ( 'T', 'F' ) ) enable;

alter table dirkspzm32.isi_artikel
    add constraint chk_isi_artikel_leg_zuschl
        check ( leg_zuschlag_p_1000kg is null
                or ( leg_zuschlag_p_1000kg is not null
                     and einsatzgewicht_kg is not null
                     and leg_zuschlag_artikel_id is not null ) ) enable;

alter table dirkspzm32.isi_artikel
    add constraint pk_artikel primary key ( artikel_id )
        using index enable;

alter table dirkspzm32.isi_artikel add constraint uk_artikel unique ( artikel )
    using index enable;

alter table dirkspzm32.isi_artikel add constraint uk_artikel_kurz unique ( artikel_kurz )
    using index enable;


